  "trivia": [
    {
      "id": "2026-48-teams",
      "year": 2026,
      "category": "format",
      "fact": "2026 will be the first World Cup with 48 teams (up from 32). Format: 12 groups of 4 → top 2 + 8 best 3rd-place teams advance to a Round of 32 → R16 → QF → SF → 3rd → Final. Total of 104 matches (up from 64 in 2022).",
      "teams": []
    },
    {
      "id": "2026-three-host-nations",
      "year": 2026,
      "category": "firsts",
      "fact": "2026 will be the first World Cup ever co-hosted by three nations: USA, Canada, and Mexico. Mexico will become the first nation to host three World Cups (1970, 1986, 2026). The final will be at MetLife Stadium in East Rutherford, NJ.",
      "teams": [
        "United States",
        "Canada",
        "Mexico"
      ]
    }
  ],
